                cat = 'Sports'
                break
    if not cat:
        for kw in biz_kw:
            if kw in text:
                cat = 'Business'
                break
    if not cat:
        cat = 'World'
    counts[cat] += 1
    classification[aid] = {'category': cat, 'title': doc['title'] if doc else None}
# totals
total = len(all_ids)
sci = counts['Science/Technology']
# fraction
from fractions import Fraction
fr = Fraction(sci, total)
percent = round(100.0 * sci / total, 2) if total>0 else None
result = {
    'science_count': sci,
    'total_count': total,
    'fraction': f"{fr.numerator}/{fr.denominator}",
    'percentage': percent,
    'counts_by_category': counts
}
print("__RESULT__:")
print(json.dumps(result))

